#include<bits/stdc++.h>
using namespace std;
#define MAXN 10010
int n,ans,len[MAXN],vis[MAXN];
vector<int> p[MAXN];
int dfs(int x) {
    if(vis[x])return vis[x];
    for(int i=0;i<p[x].size();i++)vis[x]=max(vis[x],dfs(p[x][i]));
    vis[x]+=len[x];
    return vis[x];
}
int main(void){
    cin>>n;
    for (int i=1;i<=n;i++){
        int x,y;
        cin>>x>>len[x];
        while(cin>>y)
            if(!y)break;
            else p[y].push_back(x);
    }
    for(int i=1;i<=n;i++)ans=max(ans,dfs(i));
    cout<<ans;
    return false;
}
